require "event.BaseEvent"

EnderDragonEvent = class("EnderDragonEvent", BaseEvent)

function EnderDragonEvent:onTriggered(...)
    local param1 = StringUtil.split(self.config.param1 or "1#0", "#")
    local id = tonumber(param1[1])
    local itemId = tonumber(param1[2])
    local pos = StringUtil.split(self.config.param2 or "0#0#0", "#")
    local position = VectorUtil.newVector3(pos[1], pos[2], pos[3])
    local hp = tonumber(self.config.param3)
    local players = PlayerManager:getPlayers()
    local random = math.random(1, #players)
    local lifeTime = tonumber(self.config.time)

    local userId = GameMatch:getMostKiller()
    local dragonKnight = PlayerManager:getPlayerByUserId(userId)
    if dragonKnight == nil then
        for index, player in pairs(players) do
            if index >= random then
                if player.isLife then
                    dragonKnight = player
                    break
                end
            end
        end
    end
    if not dragonKnight then
        return
    end
    GameMatch.DragonKnightName = dragonKnight.name
    if dragonKnight:ifOnMount() then

        dragonKnight:takeOffMount()
    end
    GamePacketSender:sendSetLuckySkyView(dragonKnight.rakssid)
    GameEnderDragon.new(id, position, hp, lifeTime, itemId, dragonKnight)
end